-- Q-005  수학 미적분 | 미분 | 단답형 | 난이도 C
INSERT INTO questions (
  id, lecture_id, academy_id, teacher_id, subject_id, question_type_id,
  type_code, content, answer_type, correct_answer, explanation,
  difficulty, status, reviewed_at, reviewed_by, created_at, updated_at
) VALUES (
  '00000000-0000-0000-0003-000000000005',
  '00000000-0000-0000-0002-000000000004',
  '00000000-0000-0000-0001-000000000001',
  '00000000-0000-0000-0000-000000000002',
  (SELECT id FROM subjects WHERE code = 'MATH_CALC'),
  (SELECT id FROM question_types WHERE code = 'MATH_CALC_EXTREMUM'),
  'MATH_CALC_EXTREMUM',
  E'[문제] 함수 f(x) = x³ - 3x² + 2의 극댓값과 극솟값의 합을 구하시오.',
  'short_answer', '0',
  'f''(x) = 3x² - 6x = 3x(x-2). f''(x)=0 → x=0 또는 x=2.\n증감표: x<0 증가, 0<x<2 감소, x>2 증가.\n극댓값: f(0) = 0 - 0 + 2 = 2\n극솟값: f(2) = 8 - 12 + 2 = -2\n합: 2 + (-2) = 0',
