-- Q-006  영어 독해 | 빈칸 추론 | 객관식 | 난이도 C
INSERT INTO questions (
  id, lecture_id, academy_id, teacher_id, subject_id, question_type_id,
  type_code, content, answer_type, correct_answer, explanation,
  difficulty, status, reviewed_at, reviewed_by, created_at, updated_at
) VALUES (
  '00000000-0000-0000-0003-000000000006',
  '00000000-0000-0000-0002-000000000005',
  '00000000-0000-0000-0001-000000000001',
  '00000000-0000-0000-0000-000000000003',
  (SELECT id FROM subjects WHERE code = 'ENG_READING'),
  (SELECT id FROM question_types WHERE code = 'ENG_READ_INFER_BLANK'),
  'ENG_READ_INFER_BLANK',
  E'[지문] The ability to delay gratification is one of the most powerful predictors of success in life. Individuals who can resist immediate rewards in favor of larger, future benefits tend to achieve more in academics, careers, and relationships. This capacity, often referred to as self-control or willpower, is not merely a fixed trait but can be __________ through practice and deliberate effort.\n\n[문제] 빈칸에 들어갈 말로 가장 적절한 것은?',
  'multiple_choice', '3',
  '지문의 핵심은 자기 통제력(self-control)이 고정된 특성이 아니라 연습을 통해 향상될 수 있다는 것이다. 빈칸은 "can be _____ through practice"로, "strengthened(강화되다)"가 문맥에 가장 적절하다. ①inherited(타고나다)는 "not merely a fixed trait"와 모순, ②reduced는 반대 의미, ④⑤는 논리적 흐름과 무관하다.',
  'C', 'approved', '2026-04-01 17:00:00+09',
  '00000000-0000-0000-0000-000000000001',
  '2026-04-01 16:00:00+09', '2026-04-01 17:00:00+09'
)
ON CONFLICT (id) DO NOTHING;

