-- Q-007  영어 독해 | 주제·요지 | 객관식 | 난이도 A
INSERT INTO questions (
  id, lecture_id, academy_id, teacher_id, subject_id, question_type_id,
  type_code, content, answer_type, correct_answer, explanation,
  difficulty, status, reviewed_at, reviewed_by, created_at, updated_at
) VALUES (
  '00000000-0000-0000-0003-000000000007',
  '00000000-0000-0000-0002-000000000005',
  '00000000-0000-0000-0001-000000000001',
  '00000000-0000-0000-0000-000000000003',
  (SELECT id FROM subjects WHERE code = 'ENG_READING'),
  (SELECT id FROM question_types WHERE code = 'ENG_READ_MAIN'),
  'ENG_READ_MAIN',
  E'[지문] Exercise has long been known to benefit physical health, but recent research suggests its impact extends far beyond the body. Regular physical activity has been shown to improve mood, reduce anxiety, and enhance cognitive function. Studies indicate that even moderate exercise, such as a 30-minute walk, can significantly boost memory and attention span by increasing blood flow to the brain.\n\n[문제] 윗글의 주제로 가장 적절한 것은?',
  'multiple_choice', '3',
  '지문은 운동이 신체 건강을 넘어 기분 개선, 불안 감소, 인지 기능 향상에 기여한다는 내용이다. 따라서 주제는 ③ "mental and cognitive benefits of regular exercise"가 가장 적절하다. ①은 강도 높은 운동에 한정, ②는 식이요법과 뇌 기능으로 지문 내용과 무관하다.',
  'A', 'approved', '2026-04-01 17:00:00+09',
  '00000000-0000-0000-0000-000000000001',
  '2026-04-01 16:00:00+09', '2026-04-01 17:00:00+09'
)
