INSERT INTO qa_messages (id, session_id, role, content, is_escalated, created_at) VALUES
-- 박지호의 Q&A (극한 부정형)
(
  '00000000-0000-0000-0009-000000000001',
  '00000000-0000-0000-0006-000000000001',
  'user',
  'lim(x→2) (x²-4)/(x-2)를 풀 때 왜 바로 대입하면 안 되나요? 분모가 0이 되는 건 알겠는데, 인수분해 말고 다른 방법은 없나요?',
  false,
  '2026-03-25 09:00:00+09'
),
(
  '00000000-0000-0000-0009-000000000002',
  '00000000-0000-0000-0006-000000000001',
  'ai',
  E'좋은 질문이에요! x=2를 바로 대입하면 분모가 0이 되어 정의되지 않습니다. 이런 0/0 부정형을 처리하는 방법은 세 가지가 있어요.\n\n1. **인수분해법**: x²-4 = (x-2)(x+2)로 분해 → (x+2)로 약분 → x→2 대입 = 4\n\n2. **로피탈 법칙**: 분자·분모를 각각 미분 → 2x/1 → x=2 대입 = 4 (수능에서는 주로 미적분 선택과목에서 활용)\n\n3. **유리화**: 분자나 분모에 루트가 있을 때 켤레식을 곱하는 방법\n\n수능에서는 대부분 **인수분해법**이 핵심입니다. 분자를 인수분해해서 (x-a) 인수를 찾아 약분하는 패턴을 연습하세요!',
  false,
  '2026-03-25 09:01:00+09'
),
(
  '00000000-0000-0000-0009-000000000003',
  '00000000-0000-0000-0006-000000000001',
  'user',
  '로피탈 법칙은 수능에서 쓸 수 있나요? 미적분 선택한 저한테 유리한가요?',
  false,
  '2026-03-25 09:03:00+09'
),
(
  '00000000-0000-0000-0009-000000000004',
  '00000000-0000-0000-0006-000000000001',
  'ai',
  E'미적분 선택자라면 로피탈 법칙을 알고 있으면 도움이 되지만, **수능 출제 범위에는 공식적으로 포함되지 않습니다.** 따라서 풀이 과정에 로피탈을 쓰면 감점될 수 있어요.\n\n대신 이렇게 활용하세요:\n- 로피탈로 **정답을 빠르게 검증**하는 용도로만 사용\n- 실제 풀이는 반드시 **인수분해 또는 유리화**로 작성\n\n수능 23~30번 극한 문제는 대부분 인수분해나 치환으로 해결됩니다. 패턴을 외우는 것보다 원리를 이해하는 게 장기적으로 유리해요!',
  false,
  '2026-03-25 09:04:00+09'
),
-- 김민준의 Q&A (역전파)
(
  '00000000-0000-0000-0009-000000000011',
  '00000000-0000-0000-0006-000000000002',
  'user',
  '오차 역전파 알고리즘이 가중치를 조정한다고 하는데, 그럼 신경망의 구조(층의 수, 노드 수)는 어떻게 결정되나요? 학습으로 자동으로 바뀌나요?',
  false,
  '2026-03-11 10:00:00+09'
),
(
  '00000000-0000-0000-0009-000000000012',
  '00000000-0000-0000-0006-000000000002',
  'ai',
  E'정확한 핵심을 짚었어요! 지문에서 "오차 역전파는 가중치를 조정한다"고 했죠.\n\n**신경망의 구조(층 수, 노드 수)는 학습으로 자동으로 바뀌지 않습니다.** 이것은 설계자가 미리 결정하는 하이퍼파라미터예요.\n\n수능 지문에서 이 구분이 중요한 이유:\n- **학습으로 바뀌는 것**: 가중치(weight)\n- **학습으로 바뀌지 않는 것**: 구조(층 수, 노드 수)\n\n문제 ④번이 왜 틀렸는지 이제 확실하게 이해됐죠? "역전파가 구조를 변경한다"는 진술이 지문 내용과 다르기 때문에 오답입니다. 이처럼 수능 사실적 이해 문제는 지문의 개념과 선택지의 개념 치환을 꼼꼼히 확인해야 합니다!',
  false,
  '2026-03-11 10:02:00+09'
)
ON CONFLICT (id) DO NOTHING;


